CREATE TYPE task_status_enum AS ENUM ('To Do', 'In Progress', 'Under Review', 'Completed', 'Blocked');
CREATE TYPE task_priority_enum AS ENUM ('urgent', 'high', 'medium', 'low');

CREATE TABLE users (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(255) NOT NULL
);

CREATE TABLE tasks (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    task_title VARCHAR(255) NOT NULL,
    task_description TEXT,
    status task_status_enum NOT NULL DEFAULT 'To Do',
    priority task_priority_enum NOT NULL DEFAULT 'medium',
    due_date DATE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE task_assignees (
    task_id UUID NOT NULL REFERENCES tasks(id) ON DELETE CASCADE,
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    PRIMARY KEY (task_id, user_id)
);

CREATE TYPE support_ticket_status AS ENUM ('New', 'Open', 'In Progress', 'Pending Customer', 'Resolved', 'Closed');

CREATE TYPE support_ticket_priority AS ENUM ('Low', 'Medium', 'High', 'Urgent');

CREATE TABLE users (
    id SERIAL PRIMARY KEY,
    username VARCHAR(255) UNIQUE NOT NULL,
    email VARCHAR(255) UNIQUE NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE tickets (
    ticket_id VARCHAR(20) PRIMARY KEY DEFAULT 'STK-' || LPAD(nextval('ticket_id_seq')::text, 5, '0'),
    subject VARCHAR(255) NOT NULL,
    description TEXT NOT NULL,
    status support_ticket_status NOT NULL DEFAULT 'New',
    priority support_ticket_priority NOT NULL DEFAULT 'Medium',
    reporter_id INT NOT NULL REFERENCES users(id),
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE SEQUENCE ticket_id_seq START WITH 10000;

CREATE TABLE workspaces (
    workspace_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL UNIQUE
);

CREATE TABLE users (
    user_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    username TEXT NOT NULL UNIQUE,
    display_name TEXT NOT NULL,
    avatar_url TEXT,
    status TEXT NOT NULL DEFAULT 'offline'
);

CREATE TABLE channels (
    channel_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    workspace_id UUID NOT NULL REFERENCES workspaces(workspace_id),
    name TEXT NOT NULL,
    icon TEXT NOT NULL DEFAULT 'hashtag',
    UNIQUE (workspace_id, name)
);

CREATE TABLE user_channel_status (
    user_id UUID NOT NULL REFERENCES users(user_id),
    channel_id UUID NOT NULL REFERENCES channels(channel_id),
    unread_count INTEGER NOT NULL DEFAULT 0,
    PRIMARY KEY (user_id, channel_id)
);

CREATE TABLE direct_message_conversations (
    dm_conversation_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user1_id UUID NOT NULL REFERENCES users(user_id),
    user2_id UUID NOT NULL REFERENCES users(user_id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT unique_dm_pair UNIQUE (LEAST(user1_id, user2_id), GREATEST(user1_id, user2_id)),
    CONSTRAINT different_users CHECK (user1_id <> user2_id)
);

CREATE TABLE user_dm_status (
    user_id UUID NOT NULL REFERENCES users(user_id),
    dm_conversation_id UUID NOT NULL REFERENCES direct_message_conversations(dm_conversation_id),
    unread_count INTEGER NOT NULL DEFAULT 0,
    PRIMARY KEY (user_id, dm_conversation_id)
);

CREATE TABLE messages (
    message_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    sender_id UUID NOT NULL REFERENCES users(user_id),
    content TEXT NOT NULL,
    sent_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    channel_id UUID REFERENCES channels(channel_id),
    dm_conversation_id UUID REFERENCES direct_message_conversations(dm_conversation_id),
    CONSTRAINT message_type_check CHECK (
        (channel_id IS NOT NULL AND dm_conversation_id IS NULL) OR
        (channel_id IS NULL AND dm_conversation_id IS NOT NULL)
    )
);

CREATE TABLE departments (
    department_id VARCHAR(255) PRIMARY KEY,
    department_name VARCHAR(100) UNIQUE,
    head_of_department VARCHAR(100)
);
CREATE TABLE annual_budgets (
    budget_id VARCHAR(255) PRIMARY KEY,
    department_id VARCHAR(255),
    fiscal_year INT,
    allocated_amount DECIMAL(12, 2)
);
CREATE TABLE monthly_expenses (
    expense_id VARCHAR(255) PRIMARY KEY,
    department_id VARCHAR(255),
    expense_date DATE,
    amount DECIMAL(10, 2),
    category VARCHAR(100), -- e.g., 'Salaries', 'Software', 'Travel', 'Office Supplies'
    description TEXT
);

CREATE TABLE profiles_minimalist (
  user_id INT PRIMARY KEY,
  username VARCHAR(50) NOT NULL,
  profile_picture_url VARCHAR(255),
  bio_snippet TEXT
);

CREATE TABLE inventory_simple (
    item_id INT PRIMARY KEY,
    item_name VARCHAR(255) NOT NULL,
    quantity_on_hand INT NOT NULL,
    unit_cost DECIMAL(10, 2)
);

CREATE TABLE user_settings (
  user_id INT NOT NULL,
  setting_key VARCHAR(255) NOT NULL,
  setting_value TEXT,
  category VARCHAR(100),
  last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (user_id, setting_key),
  FOREIGN KEY (user_id) REFERENCES users(id)
);

CREATE INDEX idx_user_settings_category ON user_settings(user_id, category);

CREATE TABLE sales (
    order_id VARCHAR(255) PRIMARY KEY,
    customer_id VARCHAR(255),
    order_date DATE,
    total_amount DECIMAL(10, 2),
    is_new_customer BOOLEAN
);
CREATE TABLE order_items (
    item_id VARCHAR(255) PRIMARY KEY,
    order_id VARCHAR(255),
    product_id VARCHAR(255),
    quantity INT,
    price_per_unit DECIMAL(10, 2)
);
CREATE TABLE products (
    product_id VARCHAR(255) PRIMARY KEY,
    product_name VARCHAR(255),
    category VARCHAR(255)
);

CREATE TABLE Dashboard_Modern (
  widget_id INT PRIMARY KEY,
  widget_type VARCHAR(50),
  data_source VARCHAR(100),
  display_config JSON
);

CREATE TABLE projects (project_id INT, project_name VARCHAR, status VARCHAR);
CREATE TABLE milestones (milestone_id INT, project_id INT, milestone_name VARCHAR, due_date DATE);
CREATE TABLE tasks (task_id INT, project_id INT, assigned_to VARCHAR, completed BOOLEAN);

CREATE TABLE inventory (item_id INT, item_name VARCHAR, category VARCHAR, current_stock INT, reorder_point INT, unit_cost DECIMAL);
CREATE TABLE shipments (shipment_id INT, shipment_date DATE, destination VARCHAR);
